import logging
from logging.handlers import TimedRotatingFileHandler

# Define the log directory
LOG_DIR = '/var/log/application/'

# Create a logger object
logger = logging.getLogger('application_logger')
logger.setLevel(logging.DEBUG)

# Define log format
log_format = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')

# Create file handlers for different log levels
file_handler_debug = TimedRotatingFileHandler(f'{LOG_DIR}debug.log', when='midnight', interval=1, backupCount=7)
file_handler_info = TimedRotatingFileHandler(f'{LOG_DIR}info.log', when='midnight', interval=1, backupCount=7)
file_handler_warning = TimedRotatingFileHandler(f'{LOG_DIR}warning.log', when='midnight', interval=1, backupCount=7)
file_handler_error = TimedRotatingFileHandler(f'{LOG_DIR}error.log', when='midnight', interval=1, backupCount=7)

# Set log level and format for each handler
file_handler_debug.setLevel(logging.DEBUG)
file_handler_info.setLevel(logging.INFO)
file_handler_warning.setLevel(logging.WARNING)
file_handler_error.setLevel(logging.ERROR)

file_handler_debug.setFormatter(log_format)
file_handler_info.setFormatter(log_format)
file_handler_warning.setFormatter(log_format)
file_handler_error.setFormatter(log_format)

# Add handlers to the logger
logger.addHandler(file_handler_debug)
logger.addHandler(file_handler_info)
logger.addHandler(file_handler_warning)
logger.addHandler(file_handler_error)

# Example usage
logger.debug('This is a debug message')
logger.info('This is an info message')
logger.warning('This is a warning message')
logger.error('This is an error message')